       mode: SftpFileOpenMode.create |
       SftpFileOpenMode.truncate |
       SftpFileOpenMode.write);
   var fileSize = await inputFile.length();
   file.write(inputFile.openRead().cast(), onProgress: (progress) async {
     if (fileSize == progress) {
       uploading = false;
     }
   });
 } catch (e) {

 }
